\fancyhead[R]{Final Examination}
\fancyfoot[C]{Page \thepage\ of \pageref{LastPage}}

\setlength{\parindent}{0pt}
\setlength{\parskip}{0.6em}

% ---------- COMMANDS ----------
\newcommand{\marks}[1]{\hfill\textbf{(#1 marks)}}
\newcommand{\ansspace}{\vspace{2.5cm}}
\newcommand{\longans}{\vspace{4cm}}

\begin{document}

\begin{center}
    {\Large \textbf{NORTHERN CARIBBEAN UNIVERSITY}}\\
    \textbf{Department of Mathematics and Engineering}\\[0.5em]
    {\Large \textbf{MATH272: Calculus II}}\\
    \textbf{Final Examination -- Spring 2026}\\
\end{center}

\vspace{1em}

\textbf{Time:} 2½ Hours \\
\textbf{Instructions:}
\begin{itemize}
    \item Answer ALL questions in Section A.
    \item Answer ANY FOUR questions in Section B.
    \item Show all working clearly. Marks are awarded for method.
\end{itemize}

\vspace{1em}

% ================= SECTION A =================
\section*{SECTION A (20 Marks)}

Answer ALL questions. Each question carries 2 marks.

\Needspace{4\baselineskip}
\textbf{A1.} State the geometric interpretation of \( \int_a^b f(x)\,dx \). \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A2.} Evaluate \( \int_0^2 (3x^2 + 1)\,dx \). \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A3.} State the washer method formula. \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A4.} Differentiate \( f(x) = \ln(x^2 + 1) \). \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A5.} Simplify \( \ln(6x) - \ln(3) \). \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A6.} Evaluate \( \int e^{2x} dx \). \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A7.} State integration by parts. \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A8.} Evaluate \( \int \frac{2x}{x^2+1} dx \). \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A9.} State a suitable substitution for \( \sqrt{9 - x^2} \). \marks{2}
\ansspace

\Needspace{4\baselineskip}
\textbf{A10.} Decompose \( \frac{3x+5}{(x+1)(x+2)} \). \marks{2}
\ansspace

\newpage

% ================= SECTION B =================
\section*{SECTION B (80 Marks)}

Answer ANY FOUR questions. Each question carries 20 marks.

% ---------- B1 ----------
\Needspace{12\baselineskip}
\textbf{B1.}
\begin{enumerate}[label=(\alph*)]
\item Solve \( x^2 = 3x \). \marks{6}
\longans

\item Find the area between \( y = 3x \) and \( y = x^2 \). \marks{7}
\longans

\item Find the arc length of \( y = \frac{1}{2}x^2 \), \( 0 \le x \le 2 \). \marks{7}
\longans
\end{enumerate}

\newpage

% ---------- B2 ----------
\Needspace{12\baselineskip}
\textbf{B2.}
\begin{enumerate}[label=(\alph*)]
\item Solve \( x = x^2 \). \marks{6}
\longans

\item Using the washer method, find the volume formed between 
\( y = x^2 \) and \( y = x^4 \) about the x-axis. \marks{7}
\longans

\item Using the shell method, find the volume formed by rotating 
\( y = x^2 \), \( 0 \le x \le 1 \), about the y-axis. \marks{7}
\longans
\end{enumerate}

\newpage

% ---------- B3 ----------
\Needspace{12\baselineskip}
\textbf{B3.}
\begin{enumerate}[label=(\alph*)]
\item Differentiate \( y = x^x \). \marks{6}
\longans

\item A population starts at 500 and grows according to \( P(t) = 500e^{kt} \).
If it doubles in 3 hours, find \( k \) and the population after 10 hours. \marks{7}
\longans

\item Simplify \( \ln(8x^3) - \ln(2x) \) and hence solve 
\( \ln(8x^3) - \ln(2x) = 2 \). \marks{7}
\longans
\end{enumerate}

\newpage

% ---------- B4 ----------
\Needspace{12\baselineskip}
\textbf{B4.}
\begin{enumerate}[label=(\alph*)]
\item Differentiate \( y = \sin^{-1}(3x) \). \marks{6}
\longans

\item Evaluate \( \int \sin^2 x\,dx \). \marks{7}
\longans

\item Evaluate \( \int \frac{x^2}{\sqrt{9 - x^2}} dx \). \marks{7}
\longans
\end{enumerate}

\newpage

% ---------- B5 ----------
\Needspace{12\baselineskip}
\textbf{B5.}
\begin{enumerate}[label=(\alph*)]
\item Evaluate \( \int x e^x dx \). \marks{6}
\longans

\item Evaluate \( \int \frac{1}{x^2+4} dx \). \marks{7}
\longans

\item Evaluate \( \int \frac{x}{x^2+4} dx \). \marks{7}
\longans
\end{enumerate}

\newpage

% ---------- B6 ----------
\Needspace{12\baselineskip}
\textbf{B6.}
\begin{enumerate}[label=(\alph*)]
\item Decompose \( \frac{5x+3}{(x+1)(x+2)} \). \marks{6}
\longans

\item Hence evaluate the integral. \marks{7}
\longans

\item Evaluate \( \int \frac{dx}{\sqrt{16 - x^2}} \). \marks{7}
\longans
\end{enumerate}

\end{document}

