\vspace{0.5cm}

\section*{Question 1 \marks{6}}
\noindent \textbf{Marks Awarded: 4/6}

\noindent Use integration by parts to evaluate $\int x \sec^2(x) \, dx$.

\noindent \textbf{Student Answer:}

\noindent $\int x \sec^2(x) \, dx = x \tan(x) - \int \tan(x) \, dx = x \tan(x) - \ln|\sec(x)| + C$

\noindent \blue{Correct Formula: $\int u \, dv = uv - \int v \, du$}

\noindent \blue{Let $u = x$, $dv = \sec^2(x) \, dx$ \\
Then $du = dx$, $v = \tan(x)$}

\noindent \textbf{Full step-by-step solution:}
\begin{align*}
\int x \sec^2(x) \, dx &= x \tan(x) - \int \tan(x) \, dx \\
&= x \tan(x) - \int \frac{\sin(x)}{\cos(x)} \, dx \\
&= x \tan(x) + \int \frac{-\sin(x)}{\cos(x)} \, dx
\end{align*}

\noindent \blue{Let $u = \cos(x)$, then $du = -\sin(x) \, dx$}

\begin{align*}
&= x \tan(x) + \int \frac{1}{u} \, du \\
&= x \tan(x) + \ln|u| + C \\
&= x \tan(x) + \ln|\cos(x)| + C
\end{align*}

\noindent \red{Missing $+C$ initially. Correct answer is $x \tan(x) + \ln|\cos(x)| + C$, not $x \tan(x) - \ln|\sec(x)| + C$. \\
Note: $\ln|\cos(x)| = - \ln|\sec(x)|$, but the sign change was missed.}

\vspace{0.5cm}

\section*{Question 2 \marks{7}}
\noindent \textbf{Marks Awarded: 5/7}

\noindent Evaluate $\int \frac{1}{\sqrt{9 - x^2}} \, dx$.

\noindent \textbf{Student Answer:}

\noindent $\int \frac{1}{\sqrt{9 - x^2}} \, dx = \arcsin\left(\frac{x}{3}\right) + C$

\noindent \blue{Correct Formula: $\int \frac{1}{\sqrt{a^2 - x^2}} \, dx = \arcsin\left(\frac{x}{a}\right) + C$}

\noindent \blue{Let $x = 3\sin(\theta)$, then $dx = 3\cos(\theta) \, d\theta$}

\noindent \textbf{Full step-by-step solution:}
\begin{align*}
\int \frac{1}{\sqrt{9 - x^2}} \, dx &= \int \frac{1}{\sqrt{9 - (3\sin(\theta))^2}} \cdot 3\cos(\theta) \, d\theta \\
&= \int \frac{3\cos(\theta)}{\sqrt{9 - 9\sin^2(\theta)}} \, d\theta \\
&= \int \frac{3\cos(\theta)}{\sqrt{9(1 - \sin^2(\theta))}} \, d\theta \\
&= \int \frac{3\cos(\theta)}{3\sqrt{\cos^2(\theta)}} \, d\theta \\
&= \int \frac{\cos(\theta)}{\cos(\theta)} \, d\theta \\
&= \int 1 \, d\theta \\
&= \theta + C
\end{align*}

\noindent \blue{Since $x = 3\sin(\theta)$, $\sin(\theta) = \frac{x}{3}$, so $\theta = \arcsin\left(\frac{x}{3}\right)$}

\begin{align*}
\int \frac{1}{\sqrt{9 - x^2}} \, dx &= \arcsin\left(\frac{x}{3}\right) + C
\end{align*}

\noindent \red{Correct answer, but missing steps to show the working. Needs to show the trigonometric substitution.}

\vspace{0.5cm}

\section*{Question 3 \marks{7}}
\noindent \textbf{Marks Awarded: 5/7}

\noindent Evaluate $\int \frac{x^2}{\sqrt{16 + x^2}} \, dx$.

\noindent \textbf{Student Answer:}

\noindent $\int \frac{x^2}{\sqrt{16 + x^2}} \, dx = 8\ln|x + \sqrt{16 + x^2}| - \frac{x\sqrt{16 + x^2}}{2} + C$

\noindent \blue{Correct Formula: \\
$\int \frac{x^2}{\sqrt{a^2 + x^2}} \, dx = \frac{x}{2}\sqrt{a^2 + x^2} - \frac{a^2}{2} \ln|x + \sqrt{a^2 + x^2}| + C$}

\noindent \blue{Let $x = 4\tan(\theta)$, then $dx = 4\sec^2(\theta) \, d\theta$}

\noindent \textbf{Full step-by-step solution:}
\begin{align*}
\int \frac{x^2}{\sqrt{16 + x^2}} \, dx &= \int \frac{(4\tan(\theta))^2}{\sqrt{16 + (4\tan(\theta))^2}} \cdot 4\sec^2(\theta) \, d\theta \\
&= \int \frac{16\tan^2(\theta)}{\sqrt{16 + 16\tan^2(\theta)}} \cdot 4\sec^2(\theta) \, d\theta \\
&= \int \frac{64\tan^2(\theta)\sec^2(\theta)}{\sqrt{16(1 + \tan^2(\theta))}} \, d\theta \\
&= \int \frac{64\tan^2(\theta)\sec^2(\theta)}{4\sqrt{\sec^2(\theta)}} \, d\theta \\
&= \int \frac{16\tan^2(\theta)\sec^2(\theta)}{\sec(\theta)} \, d\theta \\
&= 16 \int \tan^2(\theta)\sec(\theta) \, d\theta \\
&= 16 \int (\sec^2(\theta) - 1)\sec(\theta) \, d\theta \\
&= 16 \int (\sec^3(\theta) - \sec(\theta)) \, d\theta \\
&= 16 \int \sec^3(\theta) \, d\theta - 16 \int \sec(\theta) \, d\theta
\end{align*}

\noindent \blue{Using the reduction formula $\int \sec^3(\theta) \, d\theta = \frac{1}{2} \sec(\theta)\tan(\theta) + \frac{1}{2} \ln|\sec(\theta) + \tan(\theta)| + C$}

\begin{align*}
&= 16 \left( \frac{1}{2} \sec(\theta)\tan(\theta) + \frac{1}{2} \ln|\sec(\theta) + \tan(\theta)| \right) - 16 \ln|\sec(\theta) + \tan(\theta)| + C \\
&= 8 \sec(\theta)\tan(\theta) + 8 \ln|\sec(\theta) + \tan(\theta)| - 16 \ln|\sec(\theta) + \tan(\theta)| + C \\
&= 8 \sec(\theta)\tan(\theta) - 8 \ln|\sec(\theta) + \tan(\theta)| + C
\end{align*}

\noindent \blue{Since $x = 4\tan(\theta)$, $\tan(\theta) = \frac{x}{4}$. Also, $\sec(\theta) = \frac{\sqrt{16 + x^2}}{4}$}

\begin{align*}
&= 8 \cdot \frac{\sqrt{16 + x^2}}{4} \cdot \frac{x}{4} - 8 \ln\left| \frac{\sqrt{16 + x^2}}{4} + \frac{x}{4} \right| + C \\
&= \frac{x\sqrt{16 + x^2}}{2} - 8 \ln\left| \frac{\sqrt{16 + x^2} + x}{4} \right| + C \\
&= \frac{x\sqrt{16 + x^2}}{2} - 8 \ln\left| \sqrt{16 + x^2} + x \right| + 8\ln|4| + C \\
&= \frac{x\sqrt{16 + x^2}}{2} - 8 \ln\left| \sqrt{16 + x^2} + x \right| + C'
\end{align*}

\noindent \red{The student's answer is incorrect. The correct answer is $\frac{x\sqrt{16 + x^2}}{2} - 8 \ln|x + \sqrt{16 + x^2}| + C$. The student has the wrong sign for the logarithmic term and the wrong coefficient.}

\vspace{0.5cm}

\begin{tcolorbox}
\noindent \textbf{Final Examiner Comment:}

\noindent \textbf{Strengths:}
\begin{itemize}
\item The student demonstrates a good understanding of integration by parts and trigonometric substitution.
\item The student correctly identifies the appropriate techniques for each problem.
\end{itemize}

\noindent \textbf{Weaknesses:}
\begin{itemize}
\item The student needs to show more working, especially for trigonometric substitutions.
\item The student makes errors with signs and coefficients.
\item The student needs to remember the constant of integration.
\end{itemize}

\noindent \textbf{Why marks were lost:}
\begin{itemize}
\item Marks were lost due to missing steps, incorrect answers, and a failure to show sufficient working.
\end{itemize}

\noindent \textbf{How to improve to 100\%:}
\begin{itemize}
\item Practice more problems involving integration by parts and trigonometric substitution.
\item Pay close attention to detail and double-check all calculations.
\item Show all steps in the solution process.
\end{itemize}
\end{tcolorbox}

